callGraph.callee:
fetch("/api/connect/profile-pictures")
      .then((r) => (r.ok ? r.json() : null))
      .then((data: { igPicture?: string | null } | null) => {
        if (data?.igPicture) setIgPicture(data.igPicture);
      })
      .catch

(async () => {
      try {
        const res = await fetch("/api/install/meta-app");
        const data = (await res.json()) as ApiState;
        if (data.configured) {
          const saved = typeof window !== "undefined" ? window.localStorage.getItem(PROGRESS_KEY) : null;
          if (saved) {
            const parsed = JSON.parse(saved) as { phase: Phase; step: number };
            setPhase(parsed.phase);
            setStep(parsed.step);
          } else {
            setPhase("B");
            setStep(1);
          }
        }
      } catch {
        // 첫 진입 — 그대로 Phase A 시작
      } finally {
        setBootLoading(false);
      }
    })

fetch("/api/setup/ad-accounts")
      .then((r) => r.json())
      .then((data) => {
        if (data.error) setError(data.error);
        else setAccounts(data.accounts);
        setLoading(false);
      })
      .catch

fetch("/api/instagram/recent-media?limit=20")
      .then((r) => r.json())
      .then((data) => {
        const list = (data.items ?? []) as MediaItem[];
        const filtered = list.filter((m) => m.caption?.trim());
        setItems(filtered);
        if (filtered.length > 0) setPreviewId(filtered[0].id);
        setLoading(false);
      })
      .catch
